// 1) Configuración de Ambientes y Fecha
const environments = ['AR','BO','CO','CO2','CO3','EC','PE'];
const folderName = '2025_10';

// Inicializar objeto global de estadísticas
const globalStats = {};
environments.forEach(env => { globalStats[env] = 0; });

return environments.map(env => ({
  json: {
    env,
    zipName: folderName,
    basePath: `/files_host/XML_Mails_error/${env}`,
    global_stats: globalStats
  }
}));

// Parsear salida de grep con manejo de errores y persistencia global
try {
  const env = items[0].json.env;
  const basePath = items[0].json.basePath;
  const stdout = items[0].json.stdout || '';
  const globalStats = items[0].json.global_stats;

  if (!stdout || stdout.includes('SKIP') || stdout.trim() === '') {
    return [{ json: { env, basePath, files: [], global_stats: globalStats } }];
  }

  const lines = stdout.split('\n').filter(l => l.trim() !== '');
  const byFile = new Map();

  for (const line of lines) {
    const colonIndex = line.indexOf(':');
    if (colonIndex === -1) continue;
    const filePath = line.slice(0, colonIndex);
    const match = line.slice(colonIndex + 1);

    const cleanPath = filePath.replace(/\\/g, '/');
    const entry = byFile.get(cleanPath) || { filePath: cleanPath, MailFrom: [], MailTo: [] };

    if (match.includes('<MailFrom>')) {
      const val = (match.match(/<MailFrom>([^<]*)<\/MailFrom>/i) || [])[1] || '';
      entry.MailFrom.push(val);
    } else if (match.includes('<MailTo>')) {
      const val = (match.match(/<MailTo>([^<]*)<\/MailTo>/i) || [])[1] || '';
      entry.MailTo.push(val);
    }
    byFile.set(cleanPath, entry);
  }

  const consolidated = Array.from(byFile.values()).map(r => ({
    env,
    basePath,
    archivo: r.filePath.split('/').pop(),
    MailFrom: r.MailFrom.length ? r.MailFrom[0] : 'NO_ENCONTRADO',
    MailTo: r.MailTo.length ? r.MailTo[0] : 'NO_ENCONTRADO'
  }));

  return [{ json: { env, basePath, files: consolidated, global_stats: globalStats } }];

} catch (error) {
  const envCatch = items[0].json.env || 'Unknown';
  const globalStats = items[0].json.global_stats || {};
  return [{ json: { env: envCatch, files: [], error: `Error grave al parsear: ${error.message}`, global_stats: globalStats } }];
}

// Actualizar memoria global con conteo por ambiente
const payload = items[0].json;
const previousStats = payload.global_stats || {};
const env = payload.env;
const files = payload.files || [];
const currentStats = { ...previousStats };
currentStats[env] = files.length;
return [{ json: { env, files, global_stats: currentStats } }];

// Expandir filas para CSV y mantener global_stats en el primer item
const payload = items[0].json;
const rows = (payload.files || []).map(f => ({ json: { Archivo: f.archivo, MailFrom: f.MailFrom, MailTo: f.MailTo, Ambiente: payload.env } }));
if (!rows.length) {
  return [{ json: { Archivo: 'SIN_ZIP_O_CARPETA_VACIA', MailFrom: '-', MailTo: '-', Ambiente: payload.env, global_stats: payload.global_stats } }];
}
rows[0].json.global_stats = payload.global_stats;
return rows;

// Generar Reporte HTML final con los conteos acumulados
const initialItems = $('Configuracion (Env + Fecha)').all();
const finalStatsItem = $('Reinyectar memoria').first().json;
if (!finalStatsItem || !finalStatsItem.global_stats) {
  return [{ json: { html_report: 'Error: No se encontró la data final. global_stats no disponible.' } }];
}
const finalStats = finalStatsItem.global_stats;
let html = `\n<table style="border-collapse: collapse; width: 300px; font-family: Arial, sans-serif;">\n  <tr style="background-color: #f2f2f2;">\n    <th style="border: 1px solid #ddd; padding: 8px; text-align: left;">Entorno</th>\n    <th style="border: 1px solid #ddd; padding: 8px; text-align: right;">Cantidad archivos</th>\n  </tr>`;
initialItems.forEach(item => {
  const env = item.json.env;
  const count = finalStats[env] ?? 0;
  html += `\n  <tr>\n    <td style="border: 1px solid #ddd; padding: 8px;">${env}</td>\n    <td style="border: 1px solid #ddd; padding: 8px; text-align: right;">${count}</td>\n  </tr>`;
});
html += '</table>';
return [{ json: { html_report: html } }];
